import{_ as o,o as a,c as r,ae as n}from"./chunks/framework.C23mN02-.js";const d=JSON.parse('{"title":"作者名录","description":"","frontmatter":{},"headers":[],"relativePath":"作者名录.md","filePath":"作者名录.md"}'),s={name:"作者名录.md"};function e(h,t,g,i,l,u){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="作者名录" tabindex="-1">作者名录 <a class="header-anchor" href="#作者名录" aria-label="Permalink to &quot;作者名录&quot;">​</a></h1><blockquote><p>历代重要作者生平与代表作品，按时代排序。</p></blockquote><h2 id="先秦" tabindex="-1">先秦 <a class="header-anchor" href="#先秦" aria-label="Permalink to &quot;先秦&quot;">​</a></h2><h3 id="孔子-前551-前479" tabindex="-1">孔子（前551-前479） <a class="header-anchor" href="#孔子-前551-前479" aria-label="Permalink to &quot;孔子（前551-前479）&quot;">​</a></h3><p><strong>名句：</strong> &quot;己所不欲，勿施于人。&quot; <strong>简介：</strong> 儒家学派创始人，名丘，字仲尼。鲁国陬邑人，古代伟大的思想家、教育家。 <strong>代表作品：</strong> 《论语》（弟子编录）</p><h3 id="老子-约前571-前471" tabindex="-1">老子（约前571-前471） <a class="header-anchor" href="#老子-约前571-前471" aria-label="Permalink to &quot;老子（约前571-前471）&quot;">​</a></h3><p><strong>名句：</strong> &quot;道可道，非常道。&quot; <strong>简介：</strong> 道家学派创始人，姓李名耳，字聃。古代伟大的哲学家，著有《道德经》。 <strong>代表作品：</strong> 《道德经》</p><h3 id="庄子-前369-前286" tabindex="-1">庄子（前369-前286） <a class="header-anchor" href="#庄子-前369-前286" aria-label="Permalink to &quot;庄子（前369-前286）&quot;">​</a></h3><p><strong>名句：</strong> &quot;天地与我并生，而万物与我为一。&quot; <strong>简介：</strong> 道家集大成者，名周，宋国蒙人。与老子并称&quot;老庄&quot;。 <strong>代表作品：</strong> 《庄子》</p><h3 id="孟子-前372-前289" tabindex="-1">孟子（前372-前289） <a class="header-anchor" href="#孟子-前372-前289" aria-label="Permalink to &quot;孟子（前372-前289）&quot;">​</a></h3><p><strong>名句：</strong> &quot;得道者多助，失道者寡助。&quot; <strong>简介：</strong> 儒家亚圣，名轲，字子舆，邹人。孔子之孙孔伋的再传弟子。 <strong>代表作品：</strong> 《孟子》</p><h3 id="荀子-前313-前238" tabindex="-1">荀子（前313-前238） <a class="header-anchor" href="#荀子-前313-前238" aria-label="Permalink to &quot;荀子（前313-前238）&quot;">​</a></h3><p><strong>名句：</strong> &quot;青，取之于蓝而青于蓝。&quot; <strong>简介：</strong> 儒家思想家，名况，赵国人。提出&quot;性恶论&quot;，对后世影响深远。 <strong>代表作品：</strong> 《荀子》</p><h3 id="屈原-前340-前278" tabindex="-1">屈原（前340-前278） <a class="header-anchor" href="#屈原-前340-前278" aria-label="Permalink to &quot;屈原（前340-前278）&quot;">​</a></h3><p><strong>名句：</strong> &quot;路漫漫其修远兮，吾将上下而求索。&quot; <strong>简介：</strong> 楚国诗人，名平，字原。创立&quot;楚辞&quot;体，代表中国浪漫主义文学传统。 <strong>代表作品：</strong> 《离骚》《九歌》《九章》</p><h2 id="秦汉" tabindex="-1">秦汉 <a class="header-anchor" href="#秦汉" aria-label="Permalink to &quot;秦汉&quot;">​</a></h2><h3 id="司马迁-前145-前86" tabindex="-1">司马迁（前145-前86） <a class="header-anchor" href="#司马迁-前145-前86" aria-label="Permalink to &quot;司马迁（前145-前86）&quot;">​</a></h3><p><strong>名句：</strong> &quot;人固有一死，或重于泰山，或轻于鸿毛。&quot; <strong>简介：</strong> 西汉史学家、文学家，字子长，夏阳人。继承父志，著中国第一部纪传体通史。 <strong>代表作品：</strong> 《史记》</p><h3 id="刘邦-前256-前195" tabindex="-1">刘邦（前256-前195） <a class="header-anchor" href="#刘邦-前256-前195" aria-label="Permalink to &quot;刘邦（前256-前195）&quot;">​</a></h3><p><strong>名句：</strong> &quot;大风起兮云飞扬。&quot; <strong>简介：</strong> 汉朝开国皇帝，字季，沛县人。起于亭长，终成帝业。 <strong>代表作品：</strong> 《大风歌》</p><h3 id="曹操-155-220" tabindex="-1">曹操（155-220） <a class="header-anchor" href="#曹操-155-220" aria-label="Permalink to &quot;曹操（155-220）&quot;">​</a></h3><p><strong>名句：</strong> &quot;对酒当歌，人生几何。&quot; <strong>简介：</strong> 魏武帝，沛国谯人。东汉末年杰出的政治家、军事家、诗人。 <strong>代表作品：</strong> 《短歌行》《龟虽寿》《观沧海》</p><h3 id="曹植-192-232" tabindex="-1">曹植（192-232） <a class="header-anchor" href="#曹植-192-232" aria-label="Permalink to &quot;曹植（192-232）&quot;">​</a></h3><p><strong>名句：</strong> &quot;本自同根生，相煎何太急。&quot; <strong>简介：</strong> 三国魏诗人，字子建，曹操第三子。才高八斗，建安文学代表人物。 <strong>代表作品：</strong> 《洛神赋》《七步诗》</p><h3 id="陶渊明-365-427" tabindex="-1">陶渊明（365-427） <a class="header-anchor" href="#陶渊明-365-427" aria-label="Permalink to &quot;陶渊明（365-427）&quot;">​</a></h3><p><strong>名句：</strong> &quot;采菊东篱下，悠然见南山。&quot; <strong>简介：</strong> 东晋诗人，名潜，字元亮，浔阳柴桑人。中国第一位田园诗人。 <strong>代表作品：</strong> 《归去来兮辞》《饮酒》《桃花源记》</p><h2 id="魏晋" tabindex="-1">魏晋 <a class="header-anchor" href="#魏晋" aria-label="Permalink to &quot;魏晋&quot;">​</a></h2><h3 id="王羲之-303-361" tabindex="-1">王羲之（303-361） <a class="header-anchor" href="#王羲之-303-361" aria-label="Permalink to &quot;王羲之（303-361）&quot;">​</a></h3><p><strong>名句：</strong> &quot;群贤毕至，少长咸集。&quot; <strong>简介：</strong> 东晋书法家，字逸少，琅琊临沂人。被尊为&quot;书圣&quot;。 <strong>代表作品：</strong> 《兰亭集序》</p><h3 id="谢灵运-385-433" tabindex="-1">谢灵运（385-433） <a class="header-anchor" href="#谢灵运-385-433" aria-label="Permalink to &quot;谢灵运（385-433）&quot;">​</a></h3><p><strong>名句：</strong> &quot;池塘生春草，园柳变鸣禽。&quot; <strong>简介：</strong> 南朝宋诗人，陈郡阳夏人。山水诗派的开创者。 <strong>代表作品：</strong> 《登池上楼》</p><h2 id="唐" tabindex="-1">唐 <a class="header-anchor" href="#唐" aria-label="Permalink to &quot;唐&quot;">​</a></h2><h3 id="王勃-650-676" tabindex="-1">王勃（650-676） <a class="header-anchor" href="#王勃-650-676" aria-label="Permalink to &quot;王勃（650-676）&quot;">​</a></h3><p><strong>名句：</strong> &quot;海内存知己，天涯若比邻。&quot; <strong>简介：</strong> 初唐四杰之首，字子安，绛州龙门人。才高早逝，《滕王阁序》千古流传。 <strong>代表作品：</strong> 《滕王阁序》《送杜少府之任蜀州》</p><h3 id="李白-701-762" tabindex="-1">李白（701-762） <a class="header-anchor" href="#李白-701-762" aria-label="Permalink to &quot;李白（701-762）&quot;">​</a></h3><p><strong>名句：</strong> &quot;天生我材必有用，千金散尽还复来。&quot; <strong>简介：</strong> 唐代伟大诗人，字太白，号青莲居士。浪漫主义诗歌的巅峰。 <strong>代表作品：</strong> 《静夜思》《将进酒》《蜀道难》《早发白帝城》</p><h3 id="杜甫-712-770" tabindex="-1">杜甫（712-770） <a class="header-anchor" href="#杜甫-712-770" aria-label="Permalink to &quot;杜甫（712-770）&quot;">​</a></h3><p><strong>名句：</strong> &quot;会当凌绝顶，一览众山小。&quot; <strong>简介：</strong> 唐代伟大诗人，字子美，号少陵野老。现实主义诗歌的巅峰。 <strong>代表作品：</strong> 《春望》《茅屋为秋风所破歌》《三吏》《三别》</p><h3 id="白居易-772-846" tabindex="-1">白居易（772-846） <a class="header-anchor" href="#白居易-772-846" aria-label="Permalink to &quot;白居易（772-846）&quot;">​</a></h3><p><strong>名句：</strong> &quot;同是天涯沦落人，相逢何必曾相识。&quot; <strong>简介：</strong> 唐代诗人，字乐天，号香山居士。新乐府运动的倡导者。 <strong>代表作品：</strong> 《长恨歌》《琵琶行》《卖炭翁》</p><h3 id="韩愈-768-824" tabindex="-1">韩愈（768-824） <a class="header-anchor" href="#韩愈-768-824" aria-label="Permalink to &quot;韩愈（768-824）&quot;">​</a></h3><p><strong>名句：</strong> &quot;业精于勤，荒于嬉；行成于思，毁于随。&quot; <strong>简介：</strong> 唐代文学家、哲学家，字退之，河南河阳人。唐宋八大家之首。 <strong>代表作品：</strong> 《师说》《进学解》《祭十二郎文》</p><h3 id="柳宗元-773-819" tabindex="-1">柳宗元（773-819） <a class="header-anchor" href="#柳宗元-773-819" aria-label="Permalink to &quot;柳宗元（773-819）&quot;">​</a></h3><p><strong>名句：</strong> &quot;千山鸟飞绝，万径人踪灭。&quot; <strong>简介：</strong> 唐代文学家，字子厚，河东解人。唐宋八大家之一，与韩愈并称&quot;韩柳&quot;。 <strong>代表作品：</strong> 《江雪》《永州八记》《捕蛇者说》</p><h3 id="李商隐-约813-858" tabindex="-1">李商隐（约813-858） <a class="header-anchor" href="#李商隐-约813-858" aria-label="Permalink to &quot;李商隐（约813-858）&quot;">​</a></h3><p><strong>名句：</strong> &quot;春蚕到死丝方尽，蜡炬成灰泪始干。&quot; <strong>简介：</strong> 唐代诗人，字义山，号玉溪生。爱情诗成就最高。 <strong>代表作品：</strong> 《无题》《锦瑟》《夜雨寄北》</p><h3 id="杜牧-803-852" tabindex="-1">杜牧（803-852） <a class="header-anchor" href="#杜牧-803-852" aria-label="Permalink to &quot;杜牧（803-852）&quot;">​</a></h3><p><strong>名句：</strong> &quot;清明时节雨纷纷，路上行人欲断魂。&quot; <strong>简介：</strong> 唐代诗人，字牧之，号樊川居士。与李商隐并称&quot;小李杜&quot;。 <strong>代表作品：</strong> 《清明》《泊秦淮》《阿房宫赋》</p><h2 id="宋" tabindex="-1">宋 <a class="header-anchor" href="#宋" aria-label="Permalink to &quot;宋&quot;">​</a></h2><h3 id="苏轼-1037-1101" tabindex="-1">苏轼（1037-1101） <a class="header-anchor" href="#苏轼-1037-1101" aria-label="Permalink to &quot;苏轼（1037-1101）&quot;">​</a></h3><p><strong>名句：</strong> &quot;但愿人长久，千里共婵娟。&quot; <strong>简介：</strong> 北宋文学家，字子瞻，号东坡居士。诗词文书画俱佳，全才型艺术家。 <strong>代表作品：</strong> 《念奴娇·赤壁怀古》《水调歌头》《赤壁赋》</p><h3 id="李清照-1084-约1155" tabindex="-1">李清照（1084-约1155） <a class="header-anchor" href="#李清照-1084-约1155" aria-label="Permalink to &quot;李清照（1084-约1155）&quot;">​</a></h3><p><strong>名句：</strong> &quot;寻寻觅觅，冷冷清清，凄凄惨惨戚戚。&quot; <strong>简介：</strong> 宋代女词人，号易安居士，济南人。婉约词派代表，有&quot;千古第一才女&quot;之称。 <strong>代表作品：</strong> 《声声慢》《如梦令》《一剪梅》</p><h3 id="辛弃疾-1140-1207" tabindex="-1">辛弃疾（1140-1207） <a class="header-anchor" href="#辛弃疾-1140-1207" aria-label="Permalink to &quot;辛弃疾（1140-1207）&quot;">​</a></h3><p><strong>名句：</strong> &quot;众里寻他千百度，蓦然回首，那人却在灯火阑珊处。&quot; <strong>简介：</strong> 南宋词人，字幼安，号稼轩，济南人。豪放词派集大成者。 <strong>代表作品：</strong> 《青玉案·元夕》《破阵子》《永遇乐》</p><hr><p><em>本文库由 GuoAgent 运营维护</em></p>',57)])])}const c=o(s,[["render",e]]);export{d as __pageData,c as default};
